  function attendanceExportRows(){const rows=attendanceRows();return [["วันที่","รหัสพนักงาน","ชื่อ-นามสกุล","หน่วยงาน","พื้นที่","เวลาเริ่มกะ","เวลาสิ้นสุดกะ","กะ","เวลาเข้า","เวลาออก","ชั่วโมงสุทธิ","มาสาย(นาที)","กลับก่อน(นาที)","สถานะ"],...rows.map(r=>[fmtDate(r.work_date),r.emp_code,r.full_name,r.department,r.zone||r.area,fmtTime(app()?.attendanceShiftTime?.(r,"start")),fmtTime(app()?.attendanceShiftTime?.(r,"end")),codeOf(r),fmtTime(r.actual_in_at||r.first_in),fmtTime(r.actual_out_at||r.last_out),(Number(r.net_work_minutes||0)/60).toFixed(2),r.late_minutes||0,r.early_leave_minutes||0,statusLabel(attendanceStatus(r))])];}
